+/**
+ * Sanitize SVG content to prevent XSS attacks
+ * @param {string} svgContent - The SVG content to sanitize
+ * @returns {string} - Sanitized SVG content safe for DOM insertion
+ */
+const sanitizeSvg = function (svgContent) {
+    // List of dangerous patterns that could lead to XSS
+    const dangerousPatterns = [
+        /<script[\s\S]*?<\/script>/gi,
+        /javascript:/gi,
+        /on\w+\s*=/gi,
+        /data:/gi,
+        /<iframe/gi,
+        /<object/gi,
+        /<embed/gi,
+        /<link/gi,
+        /<import/gi
+    ];
+
+    let sanitized = svgContent;
+
+    // Remove script tags entirely
+    sanitized = sanitized.replace(/<script[\s\S]*?<\/script>/gi, '');
+
+    // Remove event handler attributes (onload, onclick, onerror, etc.)
+    sanitized = sanitized.replace(/\s*on\w+\s*=\s*(['"])[^\1]*?\1/gi, '');
+    sanitized = sanitized.replace(/\s*on\w+\s*=\s*[^\s>]+/gi, '');
+
+    // Remove javascript: URIs
+    sanitized = sanitized.replace(/javascript:\s*/gi, 'unsafe:");
+
+    // Remove data: URIs (can be used for inline scripts or tracking)
+    sanitized = sanitized.replace(/data:\s*/gi, 'data-blocked:');
+
+    // Remove dangerous elements
+    sanitized = sanitized.replace(/<iframe[\s\S]*?>/gi, '');
+    sanitized = sanitized.replace(/<object[\s\S]*?>/gi, '');
+    sanitized = sanitized.replace(/<embed[\s\S]*?>/gi, '');
+    sanitized = sanitized.replace(/<link[\s\S]*?>/gi, '');
+
+    return sanitized;
+};
+
+module.exports = {
+    sanitizeSvg
+};

